var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다락방 소파에서 펠리세트 발견! 수면 중입니다!","JPN":"屋根裏部屋のソファで、フェリセットを発見！　睡眠中です！","ENG":"Félicette found! She's sleeping on the attic sofa!","TWN":"在閣樓的沙發上發現費莉塞特！正在睡覺！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"예상대로야. 녀석은 주말에 서식지를 벗어나는 법이 없거든.","JPN":"予想どおりだな。やつは週末は住処から出ないんだ。","ENG":"As anticipated. She never leaves her habitat on the weekend.","TWN":"跟我想的一樣。那傢伙週末從來不離開她的被窩。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"장비는?","JPN":"装備は？","ENG":"Is the equipment ready?","TWN":"裝備呢？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"고무 장갑과 방패로 쓸 냄비 뚜껑을 가져 왔어요.","JPN":"ゴム手袋と、盾に使う鍋のフタを持ってきました。","ENG":"I have rubber gloves and a pot lid for protection.","TWN":"我帶來橡膠手套和當作盾牌的鍋蓋。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아. 신속하게 착용하도록.","JPN":"よし。速やかに身につけるように。","ENG":"Good. Put them on, fast.","TWN":"很好，快點戴上。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"예썰!","JPN":"イエッサー！","ENG":"Yessir!","TWN":"遵命！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"주말 아침부터 왜 이러는지 설명해 주겠나?","JPN":"週末の朝からどうしてこんなことをしているのか、説明してくれないか？","ENG":"Will anyone explain what is going on?","TWN":"二位能解釋一下，週末一大早的是在做什麼嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"경기 전날에는 푹 쉬면서 컨디션 조절하자는 게 코치의 아이디어 아니었어?","JPN":"試合の前日はゆっくり休みながら体調を整えようってのが、コーチの考えじゃなかったのか？","ENG":"Wasn't it your idea to rest well before match day, Coach?","TWN":"比賽前一天好好休息，調整狀態，這不是教練的意思嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"외식 가자는 말을 그렇게 받아들일 수도 있군.","JPN":"外食に行こうという話を、そんな風に受けとることもあるんだな。","ENG":"So that's how you understood eating out as.","TWN":"呃，這個用作外出聚餐的理由可以是可以……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼. 저번에 꼬맹이 반응은 코치도 봤잖아.","JPN":"とにかく。この前のおこちゃまの反応はコーチも見ただろ？","ENG":"Anyway, you saw how she reacted last time.","TWN":"總之，上次小鬼的反應教練不是也有看到？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"가만뒀다간 경기 직전까지 시뮬레이터에 처박혀 있어야 할 걸.","JPN":"ほっといたら、試合直前までシミュレーターに引きこもり確定だよ。","ENG":"Leave her like that, and we'll be stuck in the simulator until the match.","TWN":"如果放著她不管，比賽之前她會一直待在模擬器裡。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니 곯아떨어진 채로 데리고 나가서 기정 사실로 만들어 버린다!","JPN":"だから、寝てる間に連れ出して、既成事実にしちゃうのさ！","ENG":"So, we'll take her outside while she's asleep!","TWN":"所以趁她睡著的狀態下帶出去，製造既定事實！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다시 들어도 흠잡을 데 없는 완벽한 작전이에요!","JPN":"まさに、抜け目のない完璧な作戦です！","ENG":"It's a perfect plan, no flaws whatsoever!","TWN":"再聽一遍也是沒有分毫瑕疵的完美作戰計畫！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"(말해도 안 통하겠군.)","JPN":"(話しても無駄だろうな。)","ENG":"(Talking to them is pointless.)","TWN":"（好像溝通無效。）"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미리 경고하는데, 사이코 꼬맹이는 저혈압이야.","JPN":"警告しておくけど、サイコガキは低血圧なんだ。","ENG":"I'm warning you, psycho kid gets cranky when she wakes up.","TWN":"我先警告你們，這小瘋子可是有起床氣的。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"밖으로 옮기다가 잠에서 깨면 깨물 수도 있으니까 조심하라구.","JPN":"外に運ぶ途中で目覚めたら噛まれる可能性があるから、気をつけろよ。","ENG":"She might bite you if she wakes up on the way out.","TWN":"要是在搬運過程中吵醒她的話，可是會咬人的，大家要小心。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럼 간다! 전원 돌격!!","JPN":"それじゃあ、行くぞ！　全員、突撃！！","ENG":"All right, here we go! All members, charge!","TWN":"那就動手囉！全員突擊！！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"돌겨어억!!","JPN":"突撃いぃ！！","ENG":"Chaaaarge!","TWN":"突擊！！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"크엑!? 이 꼬맹이가 어른을 걷어차!","JPN":"ぐへっ！？　おこちゃまのくせに、大人を蹴るか！","ENG":"Keh?! You little punk! Did you just kick me?!","TWN":"呃唔！？小鬼還踹人！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"갸아악! 손 물렸어요! 손!","JPN":"ぎゃああっ！　手を噛まれました！　手！","ENG":"Kyaaah! She bit me! She bit my hand!","TWN":"哎呀呀呀！她咬我的手！我的手手！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"코치! 팔 잡아! 팔!","JPN":"コーチ！　腕を掴め！　腕！","ENG":"Coach! Grab her by the arms! The arms, I said!","TWN":"教練！抓住她的手臂！手臂！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으음, 흠냐……. ","JPN":"うーん、むにゃ…… ","ENG":"...Mm, *Yawn*...","TWN":"呃嗯，唔嗯……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":" 응?","JPN":" ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 일어났구나. 펠리세트.","JPN":"あ、起きたんだね。フェリセット。","ENG":"Oh, you're awake, Félicette.","TWN":"你醒啦，費莉塞特。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"졸리면 더 쉬어도 돼.","JPN":"眠かったらもっと休んでてもいいよ。","ENG":"Rest more if you're tired.","TWN":"睏的話就再睡一會。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여긴 어디에요? 분명 전력 분석하다 소파에서 잠들었는데……?","JPN":"ここはどこですか？　確か戦力分析をしていて、ソファで寝落ちしたかと……？","ENG":"Where are we? I thought I fell asleep on the sofa while analyzing our forces...","TWN":"這裡是什麼地方？我明明記得我在分析戰力，然後在沙發上睡著了……？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"번화가에 있는 음식점. 노엘이 아침 식사가 맛있다고 추천해 줬어.","JPN":"繁華街にある食堂よ。ノエルがここの朝食がおいしいってすすめてくれたの。","ENG":"We're in a restaurant downtown. Noelle recommended the place for their breakfast menu.","TWN":"這裡是美食街的餐廳，洛艾兒說這裡的早餐很好吃，推薦大家過來吃。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"외식은 나중에 하자고 했잖아요. 하여튼 마음대로….","JPN":"外食は後でって言ったじゃないですか。まったく、勝手に……","ENG":"I told you we should eat out later. Tsk, so stubborn...","TWN":"我不是說以後再出去吃飯？哼，真是任性……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"셋 다 얼굴이 왜 그래요? 누가 할퀴었어요?","JPN":"三人とも、顔はどうしたの？　誰かにひっかかれでもした？","ENG":"Wait, what's wrong with your faces? Did something claw you?","TWN":"你們三個的臉怎麼回事？被誰抓的？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지옥에서 올라온 미친 고양이를 잡으려다가 입은 부상이야.","JPN":"地獄から這い上がってきたネコを捕まえようとして怪我したんだよ。","ENG":"I was trying to catch this crazy devil cat.","TWN":"我們是在捕捉從地獄跑出來的瘋狂貓咪時受傷的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"고양이가 아니라 새끼 호랑이였어….","JPN":"ネコではなくて、小虎だったな……","ENG":"It wasn't a cat, it was a tiger cub...","TWN":"明明就是母老虎……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으. 물린 손이 아직도 얼얼해요.","JPN":"うう。噛まれた手、まだヒリヒリします。","ENG":"Urgh. My hand still stings...","TWN":"嗚嗚，我手被咬到的地方現在還是很麻。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"자고 있는 널 데려 오느라 그랬대.","JPN":"寝てるあなたを連れ出そうとしてこうなったんだって。","ENG":"They had trouble trying to move you here while you were asleep.","TWN":"他們把你搬出來時弄的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하아….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"蛤……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"상관없죠. 훈련은 아침을 먹고 나서 하면 되니까요.","JPN":"いいでしょう。訓練は朝食を食べてからすればいいですから。","ENG":"I guess it's fine. We'll train after eating breakfast.","TWN":"無所謂，吃完早飯再訓練吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"부상자들에게 훈련을 시킬 셈인가?","JPN":"怪我人に訓練をさせるつもりか？","ENG":"You want them to train when they're all injured?","TWN":"你是打算讓傷患們訓練嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"부상자라뇨. 노엘이랑 라이카는 그냥…….","JPN":"怪我人って。ノエルとライカはただ……","ENG":"Injured? No, Laika and Noelle are just...","TWN":"這哪算受傷？洛艾兒和萊卡就是想……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배! 펠리세트에게 물린 손이 갑자기 움직이지 않아요!","JPN":"ミナ先輩！　フェリセットに噛まれた手が、急に動きません！","ENG":"Mina! The hand Félicette bit, I can't move it! It's turning cold!","TWN":"米娜前輩！我被費莉塞特咬傷的手突然動彈不得！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오늘 하루만 푹 쉬면 나을 것 같은데 어떡하죠?","JPN":"今日一日だけゆっくり休めば治りそうですけど、どうしましょう？","ENG":"Maaaaybe a good day's rest will cure it! What do I do?","TWN":"我覺得今天好好休息一天就能痊癒，怎麼辦呢？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그, 그래. 이 상태로 훈련 받긴 힘들겠네.","JPN":"そ、そう。このまま訓練するのは難しそうだね。","ENG":"R-right. You don't look like you're fit to train today.","TWN":"嗯，也是，這種狀態進行訓練是有點困難。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"스키너, 인터뷰할 때 얼굴에 난 상처는 뭐라고 설명할까?","JPN":"スキナー、インタビューの時に私の顔にできた傷はなんて説明しよっか？","ENG":"Skinner, what should I say when they ask about the scar on my face during the interview?","TWN":"史金納，採訪時我要怎麼解釋臉上的傷口？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"까딱 잘못했다가 스폰서 제의도 못 받는 거 아냐?","JPN":"下手したら、スポンサーの提案を外されるんじゃない？","ENG":"What if our sponsors decide to cut us off?","TWN":"搞不好連贊助商的合約都拿不到吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼 곤란하지. 본선에 나가려면 최소한 헬기 한 대는 필요할 텐데.","JPN":"それじゃ困るよ。本戦に出るためには、少なくともヘリ1機は必要なのに。","ENG":"Oh, that won't do. We'll need at least one chopper to get to the elimination round.","TWN":"那可不行。決賽裡想贏，隊裡至少還需要一架直升機。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"큭. 이 게으름뱅이들.","JPN":"くっ。この怠け者たち。","ENG":"Kgh, you lazy idiots...","TWN":"哼，你們這些賴皮鬼。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘은 팀원들의 컨디션 관리에 집중하게나.","JPN":"今日はチームメンバーの体調管理に集中したまえ。","ENG":"Focus on managing the team's condition for today.","TWN":"今天就讓隊員們專注在恢復狀態吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"코치로서 하는 지시일세.","JPN":"コーチとしての指示だ。","ENG":"That's an instruction, as your coach.","TWN":"這是教練的指示。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……알겠어요. 그럼 오늘 훈련은 쉴게요.","JPN":"……わかりました。それじゃあ、今日の訓練は休むことにします。","ENG":"...Fine. I'll skip today's training, then.","TWN":"……好吧。那今天就暫停訓練。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"마침 좋은 기회네요! 샤레이드에 올 때 혼신의 힘을 다해 짜 둔 관광 코스가 있거든요!","JPN":"ちょうどよかったです！　シャレードに来る時、渾身の力を込めて組んだ観光コースがあるんですよ！","ENG":"This is great news! I have a thoroughly planned tour that I made on my way to Charade!","TWN":"那正是個好機會！來查雷德的時候，我絞盡腦汁計畫了一個完美的旅遊路線！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"아직 포기 안 하고 있었군.","JPN":"まだあきらめていなかったんだな。","ENG":"You still haven't given up on that yet.","TWN":"你還沒放棄嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헷. 첫 상여금으로 산 가이드 북인데 그냥 두긴 아깝잖아요.","JPN":"へへっ。初めてのボーナスで買ったガイドブックなのに、見ないなんてもったいないじゃないですか。","ENG":"He he. It's a travel guide I bought with my first bonus salary. I didn't want it to go to waste.","TWN":"嘿嘿，這可是我用第一筆獎金買的旅遊指南，就那麼放著多可惜。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오늘 하루는 저 노엘에게 맡겨 주세요!","JPN":"今日一日は私、ノエルに任せてください！","ENG":"Leave everything up to Noelle for today!","TWN":"今天一天就交給我洛艾兒吧！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"훈련을 쉰다고 했지, 놀자고 한 적은 없어요!","JPN":"訓練を休むだけで、遊びに行こうと言ったわけではないわ！","ENG":"I said we're skipping training, not hanging out!","TWN":"我是說不用訓練，可沒說要出去玩！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너도 좋으면서 왜 그래. 사람도 기계도 일만 하면 병드는 거야.","JPN":"あんたも嬉しいくせに。人も機械も、仕事ばっかりしてると病むよ。","ENG":"Come on, don't tell me you don't like the idea. All work and no play makes everyone dull.","TWN":"你明明就很開心，幹嘛口是心非。人也好機器也好，只顧著工作的話會生病的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마세요! 코스 중에 건틀렛 박물관도 넣어 뒀거든요!","JPN":"心配しないでください！　コースの中には、ガントレット博物館もありますから！","ENG":"Don't worry! I've included the Gauntlet Museum in our tour!","TWN":"別擔心！我還有在旅遊路線中加入聖鎧博物館喔！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"건틀렛 박물관?","JPN":"ガントレット博物館？","ENG":"The Gauntlet Museum?","TWN":"聖鎧博物館？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네. 펠리세트라면 구경하고 싶어할 것 같아서요.","JPN":"はい。フェリセットなら観覧したがるだろうと思ったんで。","ENG":"Yes. I thought you would want to check it out.","TWN":"是的，因為我覺得費莉塞特應該會想參觀。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……구경이 아니라 견학이겠죠.","JPN":"……観覧じゃなくて、見学でしょう。","ENG":"...It would be a field trip, not \\"checking it out.\\"","TWN":"……不是參觀，是見習。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이 응큼한 꼬맹이. 입꼬리 올라간 것 좀 봐.","JPN":"この悪賢いおこちゃまめ。口角が上がってる。","ENG":"You sly kid. Look at you, all smiling."},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"말은 그렇게 해도 표정은 솔직하잖아.","JPN":"言葉に反して、顔は素直だな。","ENG":"It's written all over your face.","TWN":"雖然嘴硬，不過表情卻很誠實嘛。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"앙!!","JPN":"あむ！！","ENG":"Grrr!","TWN":"啊！！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"악!! 내 손가락!!","JPN":"ぎゃっ！！　私の指！！","ENG":"Ack! My finger!","TWN":"啊！！我的手指頭！！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼 우선 주문부터 할까? 많이 돌아다니려면 배가 든든해야지.","JPN":"それじゃあ、まずは注文からしようか？　たくさん歩き回るためには、お腹いっぱい食べないと。","ENG":"Should we order first? We need a good meal to keep up with that hectic schedule.","TWN":"那先點餐吧？要想多逛一會兒，得先吃飽才行。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"노엘이 그러는데 여기 달걀 샌드위치가 그렇게 맛있대요.","JPN":"ノエルが言ってたけど、ここのタマゴサンドイッチがおいしいらしいですよ。","ENG":"Noelle says that the egg sandwich is really good here.","TWN":"洛艾兒說這裡的雞蛋三明治很好吃。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그럼 나는 달걀 샌드위치로 하지.","JPN":"それでは、私はタマゴサンドイッチにしよう。","ENG":"I'll have the egg sandwich, then.","TWN":"那請給我一份雞蛋三明治。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어오 아아 에으이이오 아에요. (저도 달걀 샌드위치로 할게요.)","JPN":"ああいお、ああおあんおいっいいいあう。(私も、タマゴサンドイッチにします。)","ENG":"I ill haah aan hoo. (I will have that too.)","TWN":"凹嗚，凹嗚，凹嗚凹嗚（我也要雞蛋三明治。）"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"입에 물고 대답하지 마야야!!","JPN":"噛んだまま答えるなああ！！","ENG":"Don't answer with my finger in your mouth!!","TWN":"嘴裡咬著東西的時候不要說話！！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오늘의 첫 코스는 샤레이드 아쿠아리움입니다!","JPN":"本日、最初の場所は、シャレードアクアリウムです！","ENG":"Our first course is the Charade Aquarium!","TWN":"今天的第一站是查雷德水族館！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"관리국이 진행하는 멸종 위기 생물 복원 과정도 생생하게 관람 가능!","JPN":"管理局が行ってる絶滅危惧種の復元過程も、はっきりと観覧可能！","ENG":"You can even watch the endangered species recovery program, managed by the Administration!","TWN":"可以現場觀看管理局進行的瀕危生物復育計畫！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"귀여운 펭귄들의 애교도 놓치지 마세요!","JPN":"かわいいペンギンたちの愛嬌もお見逃しなく！","ENG":"Oh, don't miss the cute penguins as well!","TWN":"可愛企鵝的撒嬌也不容錯過喔！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"손님이 먹이로 준 정어리에 문제가 있어서 당분간 쉰다는데?","JPN":"お客さんがエサとしてあげたイワシに問題があって、しばらく休むらしいよ？","ENG":"It says that they're closed due to some problems with the fish the visitors gave them.","TWN":"說是因為客人們餵食的沙丁魚有問題，所以暫時休息？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그럴 수가…….","JPN":"そ、そんな……","ENG":"B-but...","TWN":"怎，怎麼會……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아뇨! 기왕 이렇게 된 거 바다거북을 보러 가죠!","JPN":"いいえ！　それなら、ウミガメを見に行きましょう！","ENG":"No! Let's go look at the sea turtles instead!","TWN":"不！既然如此，那我們乾脆去看海龜吧！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"바다거북? 그런 것도 있어?","JPN":"ウミガメ？　そんなのもいるの？","ENG":"Sea turtles? They have them here?","TWN":"海龜？還有那種東西？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 등껍질도 직접 만질 수 있대요!","JPN":"はい！　甲羅も直接触ることができるらしいですよ！","ENG":"Yes! You can also touch their shells!","TWN":"是的！聽說還可以親手摸摸海龜殼！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다음은 펠리세트가 기대하던 건틀렛 박물관!","JPN":"次は、フェリセットが楽しみにしてたガントレット博物館！","ENG":"Up next, Félicette's favorite! The Gauntlet Museum!","TWN":"下一站是費莉塞特期待的聖鎧博物館！"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안 했어요.","JPN":"してないわ。","ENG":"It's not my favorite.","TWN":"才不是。"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여기는 구 시가지를 전쟁 당시의 풍경 그대로 복구해 놓은 거래요.","JPN":"ここは、旧市街地を戦時中の状態に復旧しておいたんですって。","ENG":"This is where they restored the Old City during war times.","TWN":"聽說這裡是在舊城區的基礎上重現戰爭當時的原貌。"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"실감 나는 디오라마를 감상하면서 전쟁 전 이 지역 특산물로 만든 요리도 맛볼 수 있어요!","JPN":"リアリティ溢れるジオラマを鑑賞しながら、戦前のこの地域の特産物で作った料理も味わえますよ！","ENG":"We can taste the food made from the region's specialties from before the war while enjoying the realistic diorama!","TWN":"可以一邊欣賞生動的微型立體景觀，一邊品嚐戰爭爆發之前該地區的特產美食！"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"샤레이드의 화려함과 동떨어진 이색적인 분위기! 오늘 점심은 여기서 먹어요!","JPN":"派手なシャレードとはかけ離れた異色の雰囲気！　今日のランチはここで食べましょう！","ENG":"A refreshing scenery, away from Charade's flashy lights and signposts! Let's have lunch here!","TWN":"這是與查雷德的華麗相去甚遠的特色氛圍！今天的午餐就在這裡吃吧！"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기 있는 경고문은 무시해도 되는 거야?","JPN":"あそこにある警告文は無視していいの？","ENG":"Shouldn't we acknowledge that warning sign over there?","TWN":"現在是要無視那邊的警告標示嗎？"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어라, 공사 중이라네. 조용한 분위기는 아니겠는데.","JPN":"あれ、工事中だって。静かな雰囲気じゃなさそうだけど。","ENG":"Huh? It says that it's under maintenance. Doesn't sound so refreshing to me.","TWN":"哎呀，正在施工呢，那應該會很吵吧？"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이럴 수가~","JPN":"そんな～","ENG":"No way!!!","TWN":"怎麼會～"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 그래도 덕분에 실제 전쟁터 같은 현장감이 느껴지지 않을까요!","JPN":"あっ、でもおかげで、実際の戦場みたいな臨場感が感じられるんじゃないでしょうか！","ENG":"Ah, but then, maybe it'll make the atmosphere feel more realistic, just like the war!","TWN":"不過這樣我們才能感受到戰場般的臨場感吧！"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양은 정말 회복이 빠르군.","JPN":"ノエル君は本当に立ち直るのが早いな。","ENG":"Noelle sure recovers fast.","TWN":"洛艾兒恢復得可真快。"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오뚜기 같은 거 아냐? 머리에 든 게 적어서 균형을 금방 회복한다거나.","JPN":"ダルマみたいなもんじゃないか？　頭が軽くて、すぐバランスを取り戻すところとか。","ENG":"Maybe she's some kind of roly-poly toy. Or she's able to balance herself quickly because her head is so light.","TWN":"不覺得她很像不倒翁嗎？因為腦袋裡裝的東西少，所以很快就能恢復平衡。"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"자! 없는 것 빼고 다 있다! 아포칼립스의 시작!","JPN":"さあ！　ここには何でもすべてある！　アポカリプスの始まり！","ENG":"Now! Here, we have everything, everywhere, all at once! Welcome to the Apocalypse!","TWN":"到囉！什麼都賣，什麼都不奇怪的阿波卡利斯商店！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"출입구만 무려 500여 개! 도시 아래 펼쳐진 세계 최대의 스트리트 몰! 브랑겔입니다!","JPN":"出入口だけでなんと500か所！　街の下に広がった世界最大のストリートモール！　ウランゲルです！","ENG":"Five hundred entrances! The world's biggest mall ever made! This is Wrangel!","TWN":"光出入口就有500多個！世界最大的地下商場！弗蘭格爾！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"너 정말 제대로 관광만 다닐 작정이었구나……?","JPN":"本当にしっかり観光だけするつもりだったんだね……？","ENG":"You really went all in on the tourism, didn't you...?","TWN":"原來你認真是來旅遊的……？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게요. 여기서 사는 우리보다 더 잘 아는 것 같아요.","JPN":"そうね。ここに住んでる私たちより詳しいみたいだわ。","ENG":"I know, right? She knows the place better than we do. And we live here.","TWN":"對啊，比我們這些在地人還熟。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>손님 여러분께 안내 말씀드립니다.</color>","JPN":"<color=#ffd34c>お客さまにご案内いたします。</color>","ENG":"<color=#ffd34c>Attention, all visitors.</color>","TWN":"<color=#ffd34c>各位顧客，現在播報一則通知。</color>"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>잠시 후, 사전에 공지드린 대로 저희 브랑겔에서 건틀렛 예선전이 진행될 예정입니다.</color>","JPN":"<color=#ffd34c>この後、事前にご案内しました、ウランゲルにてガントレット予選が開かれる予定でございます。</color>","ENG":"<color=#ffd34c>Soon, the qualifiers for the Gauntlet League will be held at Wrangel.</color>","TWN":"<color=#ffd34c>如先前通知所說，稍後將在弗蘭格爾進行聖鎧預賽。</color>"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>경기 중 지하 2층은 쇼핑이 어렵습니다. 손님 여러분의 이해 부탁드립니다.</color>","JPN":"<color=#ffd34c>試合中、地下2階でのショッピングはご利用できません。ご了承ください。</color>","ENG":"<color=#ffd34c>Please be advised that floor B2 will be restricted and unavailable for shopping during the match. We thank you for your cooperation.</color>","TWN":"<color=#ffd34c>比賽期間地下2樓將暫時關閉，無法購物，請顧客朋友們予以諒解。</color>"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"뭣이라고라────!?","JPN":"なにぃぃ────！？","ENG":"WHAT?!","TWN":"他說什麼——！？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼 안 되죠! 다들 늦기 전에 지하 2층부터 가요! 어서요!","JPN":"そんなのダメです！　皆さん、地下2階から行きましょう！　早く！","ENG":"I won't allow it! Everyone, head to floor B2! NOW!","TWN":"那可不行！時間很趕欸！大家快去地下2樓，快點！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 다음은 대관람차거든요! 시내 한가운데 세워졌다는데 SNS에서 핫 플레이스에요!","JPN":"この次は大観覧車ですよ！　市内の真ん中に建てられたらしいんですけど、SNSで話題のスポットなんです！","ENG":"Next is the Ferris wheel! Located in the heart of downtown, it's a social media hot spot!","TWN":"下一站是摩天輪！據說就蓋在市中心，是熱門打卡地點！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"훈련보다 더 고된 일정인 것 같은데.","JPN":"訓練よりきついスケジュールだと思うが。","ENG":"This feels more exhausting than training.","TWN":"這個行程好像比訓練還累。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"동감이야……","JPN":"同感だよ……","ENG":"Agreed...","TWN":"我也有同感……"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"히야, 하루만에 도시를 다 돌아본 기분이네.","JPN":"いやあ、一日で街を全部見て回った気分だよ。","ENG":"Whew, it feels like we've gone around the whole city in one day.","TWN":"哎呀，有種一天就把整個城市都逛遍的感覺。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"난 마지막 관람차가 제일 좋았어. 역시 그 특유의 분위기가 매력적이라고 해야 하나.","JPN":"私は最後の観覧車がよかったなあ。やっぱりあの特有の雰囲気が魅力的って感じ？","ENG":"I liked the Ferris wheel best. The atmosphere there feels so special.","TWN":"我喜歡最後的摩天輪。那種獨特的氛圍很吸引人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하아, 이 놈의 업무 알람. 하여간 기분 망치는 데 선수라니까.","JPN":"はあ、この仕事アラーム。もう、雰囲気を台無しにするんだから。","ENG":"Geez, all these work notifications. They just have to ruin my mood, don't they?","TWN":"哀哀，這個可惡的工作鬧鐘，真會破壞心情。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"안내하느라 고생했어, 노엘. 야경이 정말 멋지더라.","JPN":"案内ご苦労様、ノエル。夜景が本当に素敵だった。","ENG":"Thanks for showing us around, Noelle. The night view was great.","TWN":"帶我們逛一整天辛苦囉，洛艾兒。夜景真的很漂亮。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"천만에요, 미나 선배. 첫 날 일정은 몸풀기라구요.","JPN":"どういたしまして、ミナ先輩。初日のスケジュールは準備運動ですよ。","ENG":"My pleasure, Mina. The first day is only a sneak peek!","TWN":"不客氣，米娜前輩。第一天的行程只是暖身而已。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이틀째 일정부터는 더 어마어마한 것들로 준비해 뒀어요.","JPN":"二日目のスケジュールからは、もっとすごいものを用意してます。","ENG":"On day 2, the tour will be packed with even more special attractions!","TWN":"從第二天的行程開始，我還有準備更驚人的內容！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"금융 센터에, 비행선, 우주 공항! 아직 못 가 본 맛집들까지!","JPN":"金融センターに、飛行船、宇宙港！　まだ行けていないグルメ店まで！","ENG":"Finance centers, airships, space stations! Even more must-visit restaurants!","TWN":"金融中心、飛船、航太站！還有沒去過的美食店！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"관람차가 무서웠나?","JPN":"観覧車が怖かったのか？","ENG":"Were you scared back on the Ferris wheel?","TWN":"你害怕摩天輪嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그런 건 아니에요. 이 나이에 높은 곳을 무서워할 리 없잖아요.","JPN":"そ、そんなんじゃありません。この歳で高いところが怖いわけないでしょう？","ENG":"O-of course not. I'm too old to be afraid of heights.","TWN":"不，不是的，我這個年紀怎麼會怕高。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그냥…….","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……그냥. 지시 내려 줘서 고맙다고요.","JPN":"……ただ。指示を出してくれてありがとうございます。","ENG":"...I just wanted to thank you for giving us the instruction today.","TWN":"……我只是想謝謝你今天的指示。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"가끔 이런 식으로 시간 낭비 하는 것도 즐겁네요.","JPN":"たまにこんな風に時間を潰すのも楽しいですね。","ENG":"Sometimes, I guess it's nice to waste time like this.","TWN":"偶爾這樣浪費一下時間也很開心。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"고마우면 그냥 고맙다고 할 것이지, 괜히 토 달고 앉았네.","JPN":"感謝してるならありがとうって言えばいいのに、なんで一言多いんだ？","ENG":"Just finish at thank you, you ungrateful child.","TWN":"想謝謝就直說嘛，幹嘛在那欲言又止的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그런데 오늘 너무 무리한 거 아냐? 뇌물 주기도 빠듯할 텐데.","JPN":"でも、今日無理しすぎたんじゃないか？　賄賂をくばるだけでもキツイだろ？","ENG":"By the way, aren't you going over your budget today? The budget must be pretty tight with all that bribing.","TWN":"不過會不會太打腫臉充胖子？要賄賂的錢應該也很吃緊吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뇌물?","JPN":"賄賂？","ENG":"Bribe?","TWN":"賄賂？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"뇌물이요?","JPN":"賄賂ですか？","ENG":"Bribing?","TWN":"賄賂？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"있잖아. 심판들한테 조금씩 찔러 주는 거.","JPN":"ほら。審判にちょっとずつあげるやつ。","ENG":"You know, the stuff you give to the judges.","TWN":"明知故問欸～就是稍微買通一下裁判嘛。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"스키너 말처럼 여긴 룰 위반도 들키지만 않으면 그만이거든. 로비 정도면 신사적이지.","JPN":"スキナーの言うとおり、ここはルール違反もバレなければいいんだよ。ロビー活動ぐらいなら紳士的だろ。","ENG":"Like Skinner said, it's okay as long as you don't get caught. Lobbying is pretty mild, to be honest.","TWN":"史金納不是有說，就算犯規，只要不被發現就沒問題。花錢買通算是比較斯文的做法吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……설마 안 줬어?","JPN":"……まさか、あげてないのか？","ENG":"You're not saying... that you didn't bribe anyone, are you?","TWN":"……你難道沒給？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"딱히 불법적인 방법을 선호했던 적은 없어서.","JPN":"別に、不法的なやり方は好きではないからな。","ENG":"I never took a liking for illegal methods.","TWN":"我不是很喜歡非法的手段。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니, 흑막처럼 생겼으면서 왜 바른 생활 청년 같은 소릴 하고 있어?","JPN":"いや、黒幕みたいな顔して何を堅実な若者みたいなこと言ってるんだよ？","ENG":"You look exactly like the typical final boss. Why are you starting all this ethical crap?","TWN":"等等，你一看就是幕後大Boss的感覺，怎麼會發出這種正義之聲？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼 저희가 이긴 경기 모두 편파 판정은 없었다는 거네요.","JPN":"それじゃあ、私たちが勝利した試合はみんな、正しく判定されてたってことですね。","ENG":"That means our victories were all fair and square.","TWN":"意思是，我們贏得光明正大。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"오히려 훨씬 불리한 상황에서 싸워 이긴 거였어요.","JPN":"むしろ、もっと不利な状況で戦って勝っていたんだわ。","ENG":"We won, even with the disadvantage.","TWN":"而且還是在對我們不利的情況下獲勝的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지금 이게 기뻐할 일이냐?","JPN":"これって喜ぶべきことなのか？","ENG":"Are you sure you should be happy about this?","TWN":"現在這是值得高興的事嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"사장님, 잠시 이것 좀 같이 보셔야겠어요.","JPN":"社長、ちょっとこちらを。","ENG":"Boss, you might want to take a look at this.","TWN":"老闆，你必須看一下這個。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"방금 전 관리국 건틀렛 운영회에서 보낸 메일이에요.","JPN":"先ほど管理局のガントレット運営会が送ったメールです。","ENG":"The Administration Gauntlet Committee sent us an email.","TWN":"這是剛才管理局聖鎧委員會發來的郵件。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>……검토 결과, 운영회는 그릴 파티가 제출한 사유에 대해 정당하다고 판단하였습니다.</color>","JPN":"<color=#ffd34c>……検討の結果、運営会はグリルパーティーが提出した理由が正当であると判断しました。</color>","ENG":"<color=#ffd34c>...The Committee recognizes that the reason submitted by Grill Party is valid.</color>","TWN":"<color=#ffd34c>……根據審查結果，委員會認為格里爾派提提交的理由正當合理。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>따라서 엔트리 조정을 허가하였으며, 경기는 정상 진행됩니다.</color>","JPN":"<color=#ffd34c>よって、エントリー調整を許可し、試合は正常に進行されます。</color>","ENG":"<color=#ffd34c>Therefore, we have approved their request to change the entry list. All matches will be held as scheduled.</color>","TWN":"<color=#ffd34c>故允許其調整參賽人員，比賽將如期進行。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>또한 경기 흥행을 위해 암전 기믹을 도입할 예정이므로….</color>","JPN":"<color=#ffd34c>また、試合の興行のために、暗転ギミックを導入する予定ですので……</color>","ENG":"<color=#ffd34c>Additionally, there will be a lights-out gimmick for the viewers' entertainment and...</color>","TWN":"<color=#ffd34c>另外，為提高比賽的吸引力，預計將引進夜戰機關……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"웃기고 있네.","JPN":"ふざけてやがる。","ENG":"Oh, come on!","TWN":"開什麼玩笑。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"기존 팀원들이 출전하기 어려우니까 엔트리를 바꾼다고? 경기 하루 전에?","JPN":"既存のチームメンバーが出場できないから、エントリーを変える？　試合の前日に？","ENG":"They're changing the entry list because the original players can't play? Last minute I might add?","TWN":"因為原來的隊員參賽有困難，所以變更參賽人員？還是在比賽一天前？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이러면 전력 분석도, 연습했던 전술도……","JPN":"これじゃあ戦力の分析も、練習した戦術も……","ENG":"Everything we did, the analysis, the strategies...","TWN":"這樣的話，戰力分析和戰術練習……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그동안 준비했던 것들이 전부 쓸모없어져요.","JPN":"今まで準備してきたことが全部台無しになってしまうわ。","ENG":"It's all useless now.","TWN":"還有這段時間所準備的，就都派不上用場了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그릴 파티에서 손을 쓴 건가?","JPN":"グリルパーティーが手を回したのか？","ENG":"Is Grill Party planning something?","TWN":"是格里爾派提搞的鬼嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아마도요. 이렇게까지 대범하게 일을 벌일 만한 곳은 아니긴 한데….","JPN":"たぶんそうです。ここまで大胆にことを運ぶほどの場所ではないですけど……","ENG":"Probably. They're not one to do things this boldly, though...","TWN":"我猜是的，雖然單憑他們不可能有這麼大的動作……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"놈들은 잘 쳐 줘도 2류야. 우리가 모르는 뒷배가 있겠지.","JPN":"やつらは高く評価しても二流だ。私たちの知らない後ろ盾があるんだろ。","ENG":"They're bush league, at best. They must've gotten some kind of help.","TWN":"他們再厲害也不過是二流勢力，背後一定有我們不知道的靠山。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼 어떡해요? 내일이 경기인데 사람을 새로 구할 수도 없잖아요!","JPN":"じゃあ、どうしましょう？　試合は明日なのに、新しい人を探すこともできないじゃないですか！","ENG":"What do we do, then? It's too late to get someone new!","TWN":"那怎麼辦？明天就要比賽咧，我們也不可能重新找人吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리국에 항의할 수는 없는 거야?","JPN":"管理局に抗議できないの？","ENG":"Can't we file a complaint to the Administration?","TWN":"不能向管理局抗議嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"규정상으로 문제는 안 돼. 속이 뻔히 보여서 그렇지.","JPN":"規定上では問題ないからね。白々しくてムカつくだけで。","ENG":"Theoretically, we can. It's just too obvious.","TWN":"從規定上來說是沒問題的，只是他們的用意很明顯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"누가 관여했는지 조사하려면 한참 걸릴 테고, 뇌물 때문이란 판결이 없는 상황에선…….","JPN":"誰が関与したか調査するには結構時間がかかるだろうし、賄賂のせいだという決定打がない状況では……","ENG":"It's gonna take ages to find out who's behind this, and with no evidence of lobbying...","TWN":"調查需要很長時間，加上沒有確切的證據證明他們有行賄……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"흥. 우리 같은 풋내기들은 그냥 내년도 예선 시드권만 주고 대기시킬걸.","JPN":"フン。私たちみたいな新人は、来年の予選シード権を与えて待機させるはずだ。","ENG":"Hmph. They'll probably seed us for next year's qualifiers and put us on hold.","TWN":"哼，像我們這種菜鳥，應該就是用給我們種子選手資格的方式打發掉吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네에? 그런 법이 어디있어요?!","JPN":"ええ？　そんなの、あんまりです！！","ENG":"Whaaat? How does that even work?!","TWN":"什麼？哪有這種事？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"죄송합니다, 사장님. 이렇게 나올 줄은 몰랐어요.","JPN":"すみません、社長。こう出てくるとは予想できなかったんです。","ENG":"I'm sorry, Boss. I didn't know they would come at us like this.","TWN":"對不起，老闆。我沒想到事情會變成這樣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"먼저 말씀을 드렸더라면…….","JPN":"先にお話ししていたら……","ENG":"Had I told you sooner...","TWN":"如果我提前告訴你……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"괜찮네. 애초에 그럴 마음 없었으니.","JPN":"大丈夫。そもそもその気はなかったのだからな。","ENG":"It's fine. I had no intention to bribe anyone in the first place.","TWN":"沒事，反正我本來就不打算走後門。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하지만….","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 네. 카나리아 스쿼드의 스키너입니다.","JPN":"あ、はい。カナリア・スクワッドのスキナーです。","ENG":"Hello? Yes, this is Skinner of Canary Squad.","TWN":"是，你好，我是金絲雀小隊的史金納。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"네? 지금 누구시라고…….","JPN":"はい？　今、どちら様と……？","ENG":"Excuse me? Who is this again...?","TWN":"嗯？你說你找誰……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"……잠시만요. 금방 바꿔 드리겠습니다.","JPN":"……少々お待ちください。すぐにお繋ぎします。","ENG":"...Please hold. I'll get him for you.","TWN":"……請稍等，我馬上把電話轉給他。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"받아 보셔야겠어요, 사장님.","JPN":"電話をお取りください、社長。","ENG":"I think you need to take this, Boss.","TWN":"老闆需要接這通電話。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아무래도 굉장히 높으신 분 연락인 것 같아서요.","JPN":"どうやら、相当上の方からの連絡みたいです。","ENG":"It sounds like someone very important.","TWN":"好像是高層人士的電話。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"늦게 연락드려 죄송합니다, 최고 관리자님.","JPN":"遅くなり申し訳ございません、最高管理者。","ENG":"My apologies for calling at such a late hour, Supreme Administrator.","TWN":"抱歉，這麼晚才聯繫您，最高管理者。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드의 시니어가 자네인가?","JPN":"シャレードのシニアが君か？","ENG":"Ah, you must be the Senior of Charade?","TWN":"你就是查雷德的Senior？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"예. 리하르트 베르너입니다.","JPN":"はい。リヒャルト・ベルナーと申します。","ENG":"Yes. This is Richard Werner.","TWN":"是，我是理查·韋爾納。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"소식은 전해 들었습니다. 직원들이 건틀렛에서 불미스러운 일에 연루되었다더군요.","JPN":"話は聞きました。御社の社員がガントレットで芳しくないことに巻き込まれたと。","ENG":"I heard the news. It seems that your employees were involved in some unfortunate events in the Gauntlet.","TWN":"事情我都聽說了，您的員工在聖鎧聯賽中捲入一些不愉快的事。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"룰보다는 성과. 급격한 성장의 대가로 샤레이드가 앓아 온 고질병이죠.","JPN":"ルールよりは成果。急激な成長の対価として、シャレードが悩まされてきた悪習です。","ENG":"Results over rules. It is the disease that has plagued Charade for decades, in return for its rapid development.","TWN":"結果比規則更重要，這是快速發展的代價，也是查雷德的舊疾。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 3등 시민을 선수로 기용하신 것은 의외였습니다.","JPN":"ですが、3等市民を選手として起用されたのは意外でした。","ENG":"But I must say, it was quite unexpected of you to hire grade 3 citizens.","TWN":"不過我很意外，您居然會雇傭三等市民作為參賽選手。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"단순히 건틀릿에서의 성과를 노리신 거라면 원래 직원들을 기용하셔도 됐을 텐데요.","JPN":"単にガントレットでの成果を狙っているのなら、既存の社員を起用されてもよかったはずですが。","ENG":"Should you have been aiming for results in the Gauntlet, your other employees would have been more than sufficient.","TWN":"如果您只是單純地想在聖鎧上取得好成績，那您大可以派原來的員工。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"부정행위에 조치를 취할 생각은 없나 보군.","JPN":"不正行為に対して措置を取る気はないようだな。","ENG":"I assume you don't plan on taking action for the malfeasance.","TWN":"看來你無意採取措施打擊作弊行為呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"예. 지배층의 불문율을 존중하기 때문이기도 하지만…….","JPN":"はい。支配階級の不文律を尊重しているためでもありますが……","ENG":"I'm afraid not. Primarily because I respect the unwritten law of the ruling class...","TWN":"是的，部分原因是出於尊重高層的淺規則。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다 당신의 능력을 증명하기에 이번 리그가 좋은 기회라고 판단했습니다.","JPN":"何よりあなたの能力を証明するのに、今度のリーグがいい機会であると判断しました。","ENG":"But moreover, I consider this League to be a good opportunity for you to prove your abilities.","TWN":"最重要的是，我認為這次聯賽是證明您能力的好機會。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"증명해야 할 필요가 있는 건가?","JPN":"証明する必要があるのか？","ENG":"And why should I be proving something at all?","TWN":"非證明不可嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"당신은 여태껏 막후에서 많은 문제를 처리해 오셨습니다. 그건 자명한 사실이죠.","JPN":"あなたはこれまで裏で数多くの問題を解決してきました。それは紛れもない事実です。","ENG":"All these years, you have been taking care of everything in the dark. That's an undeniable fact.","TWN":"一直以來您在幕後解決掉很多問題，這是毋庸質疑的事實。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 당신은 막후에 남는 대신, 전면에 서기로 하셨습니다.","JPN":"ですがあなたは裏にいることを辞め、表舞台に立つことになさいました。","ENG":"But instead of staying in the dark, you've decided to come forward.","TWN":"但是現在您選擇站在台前，而不是留在幕後。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"배후에서 상황을 조종하는 것과 앞에서 사람들을 이끄는 일은 분명 다릅니다.","JPN":"背後で状況を操ることと、表舞台で人々を導くことは明らかに違います。","ENG":"Controlling everything from the behind the curtain and being a leader of the people are extremely different.","TWN":"在背後操控局勢和在台前領導別人是二碼子事。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그러니 그에 걸맞은 능력을 보여 주십시오. 그렇다면 모두가 따를 수 있을 겁니다.","JPN":"ですので、それに相応しい能力を見せてください。そうすれば、みんなが従うでしょう。","ENG":"So show us that you possess the ability to do so. Should you succeed, you will earn respect from all of us.","TWN":"所以，請拿出實力證明您自己，大家才能服氣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"고려는 해 보겠네.","JPN":"考えてみよう。","ENG":"I will consider it.","TWN":"我考慮一下。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"감사합니다. 최고 관리자님.","JPN":"ありがとうございます。最高管理者。","ENG":"Thank you, Supreme Administrator.","TWN":"謝謝您，最高管理者。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"건투를 빌겠습니다. 그럼.","JPN":"ご健闘を祈ります。それでは。","ENG":"I wish you good luck. Farewell.","TWN":"祝您好運，再見。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"기다리게 해서 미안하군.","JPN":"待たせてすまないな。","ENG":"My apologies for keeping you waiting.","TWN":"抱歉，久等。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L26_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"계속 입을 다물 작정이라면 말리지 않겠지만….","JPN":"ずっと黙っているつもりならそれでも構わないが……","ENG":"I won't stop you if you wish to stay quiet...","TWN":"如果你打算繼續沉默，我也不攔著你……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"자네에게 당한 이들 중에는 국제 연합군 시절의 내 부하들도 있었어.","JPN":"君にやられた者の中には、国際連合軍時代の私の部下たちもいたのだ。","ENG":"But do remember that among the people you've killed, there are also my men from the Multinational Coalition Force.","TWN":"不過被你殺死的人中，有我在國際聯合軍隊的部下。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"나 역시 자네를 곱게 형무소로 보내 주진 않을 작정이야.","JPN":"当然私は君を素直に刑務所に引き渡すつもりはない。","ENG":"I have no intention of sending you off to prison unharmed.","TWN":"所以我也不打算讓完毫無缺地走進監獄。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그럼 심문을 계속하겠다. 테러리스트.","JPN":"それでは、尋問を続ける。テロリスト。","ENG":"Let us continue the interrogation, terrorist.","TWN":"那我們繼續吧，恐怖分子。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};